```class Solution {
    public int[] smallestTrimmedNumbers(String[] nums, int[][] queries) {
        List<int[]> result = new ArrayList<>();
        for (int[] query : queries) {
            int k = query[0], trim = query[1];
            List<String> trimmedNums = new ArrayList<>();
            for (String num : nums) {
                trimmedNums.add(num.substring(num.length() - trim));
            }
            Collections.sort(trimmedNums);
            result.add(trimmedNums.get(k - 1).equals("0") ? trimmedNums.indexOf(trimmedNums.get(k - 1)) : trimmedNums.indexOf(trimmedNums.get(k - 1).replace("0", "")));
        }
        return result.stream().mapToInt(i -> i).toArray();
    }
}```
